19	// sendDataSeqTo encodes a DATA frame with an explicit outer-seq under psk and sends
20	// it from a fresh client socket to dst. It is the seq-parameterized companion to
21	// sendDataTo, used where the resequencer must see monotonic outer-seqs across sends.
22	func sendDataSeqTo(t testing.TB, psk config.Key, dst *net.UDPAddr, pathID uint8, seq uint64, payload []byte) {
23		t.Helper()
24		cl, err := net.DialUDP("udp", &net.UDPAddr{IP: net.ParseIP("127.0.0.1")}, dst)
25		if err != nil {
26			t.Fatalf("dial %s: %v", dst, err)
27		}
28		defer cl.Close()
29		codec, err := frame.NewCodec(psk)
30		if err != nil {
31			t.Fatalf("new codec: %v", err)
32		}
33		wire, err := codec.Encode(nil, frame.Data{OuterSeq: seq, PathID: pathID, Payload: payload})
34		if err != nil {
35			t.Fatalf("encode: %v", err)
36		}
37		if _, err := cl.Write(wire); err != nil {
38			t.Fatalf("write: %v", err)
39		}
40	}
