42	// probeRound drives one healthy probe cadence step against the given path indices:
43	// emitProbes on every open path, then for each (peer, path) reads the emitted probe,
44	// reflects it, and feeds the echo back so the path's prober records a heartbeat. It
45	// advances the fake clock by one probe interval.
46	func probeRound(t testing.TB, m *Multipath, clk *fakeClock, refl *telemetry.Reflector, codec *frame.Codec, psk config.Key, peers map[int]*net.UDPConn, aps map[int]netip.AddrPort) {
47		t.Helper()
48		m.emitProbes()
49		clk.advance(testProbeRTT)
50		for idx, peer := range peers {
51			probe := readProbe(t, peer, codec)
52			raw, err := frame.Encode(psk, probe)
53			if err != nil {
54				t.Fatalf("re-encode probe: %v", err)
55			}
56			echo, err := refl.Reflect(raw)
57			if err != nil {
58				t.Fatalf("reflect path %d: %v", idx, err)
59			}
60			m.handleInbound(m.paths[idx], echo, aps[idx])
61		}
62		clk.advance(testProbeInterval - testProbeRTT)
63	}
