65	// TestMultipathAddPathAdmitsWhenHealthy is the T30 add acceptance: a path added at
66	// runtime opens its own socket + prober, is admitted to the scheduler, becomes
67	// selectable only once its probes report healthy, and disturbs neither the surviving
68	// path's remote nor the single virtual endpoint.
69	func TestMultipathAddPathAdmitsWhenHealthy(t *testing.T) {
70		psk := testKey(t, 0x31)
71		clk := newFakeClock()
72		m, probers, scheduler := newProbingMultipath(t, loopbackPaths(1), psk, clk)
73		if _, _, err := m.Open(0); err != nil {
74			t.Fatalf("Open: %v", err)
75		}
76		t.Cleanup(func() { _ = m.Close() })
77	
78		virtBefore := m.virt
79		refl := telemetry.NewReflector(psk, rand.Reader)
80		codec, _ := frame.NewCodec(psk)
81	
82		peer0, ap0 := rawPeer(t)
83		m.paths[0].setRemote(ap0)
84		primaryRemoteBefore, _ := m.paths[0].getRemote()
85	
86		// Bring the primary up.
87		for i := 0; i < testProbeUpSucc; i++ {
88			probeRound(t, m, clk, refl, codec, psk, map[int]*net.UDPConn{0: peer0}, map[int]netip.AddrPort{0: ap0})
89		}
90		if probers[0].State() != telemetry.StateUp {
91			t.Fatalf("primary state = %v, want up", probers[0].State())
92		}
93		if idx := scheduler.Pick(sched.ClassData); idx != 0 {
94			t.Fatalf("Pick = %d, want 0 (primary active)", idx)
95		}
96	
97		// --- Add a second path at runtime. ---
98		if err := m.AddPath(config.Path{Name: "runtime-b", SourceAddr: netip.MustParseAddr("127.0.0.1")}); err != nil {
99			t.Fatalf("AddPath: %v", err)
100		}
101		if len(m.paths) != 2 {
102			t.Fatalf("paths = %d, want 2 after add", len(m.paths))
103		}
104		added := m.paths[1]
105		if added.id == m.paths[0].id {
106			t.Fatalf("added path reused the primary's id %d (surviving id must be stable)", added.id)
107		}
108		if added.conn == nil {
109			t.Fatal("added path has no socket")
110		}
111		if added.prober == nil {
112			t.Fatal("added path has no prober")
113		}
114	
115		// Survivor and virtual endpoint undisturbed by the add.
116		if m.virt != virtBefore {
117			t.Fatal("virtual endpoint object changed on add (engine would see churn)")
118		}
119		if r, _ := m.paths[0].getRemote(); r != primaryRemoteBefore {
120			t.Fatalf("primary remote changed on add: %v != %v", r, primaryRemoteBefore)
121		}
122	
123		// Down until healthy: the scheduler still selects the primary.
124		if idx := scheduler.Pick(sched.ClassData); idx != 0 {
125			t.Fatalf("Pick = %d right after add, want 0 (added path not yet healthy)", idx)
126		}
127	
128		// Bring BOTH up; the added path records heartbeats and goes up.
129		peer1, ap1 := rawPeer(t)
130		added.setRemote(ap1)
131		for i := 0; i < testProbeUpSucc; i++ {
132			probeRound(t, m, clk, refl, codec, psk,
133				map[int]*net.UDPConn{0: peer0, 1: peer1}, map[int]netip.AddrPort{0: ap0, 1: ap1})
134		}
135		if added.prober.State() != telemetry.StateUp {
136			t.Fatalf("added path state = %v, want up (probes not driving its liveness)", added.prober.State())
137		}
138	
139		// Admission proof: blackhole the primary; egress fails over to the runtime-added
140		// path, which is only possible if it was admitted to the scheduler.
141		rounds := int(testProbeDownAfter/testProbeInterval) + 3
142		for i := 0; i < rounds; i++ {
143			m.emitProbes()
144			clk.advance(testProbeRTT)
145			readProbe(t, peer0, codec) // drain the primary's probe, no echo (blackhole)
146			probe := readProbe(t, peer1, codec)
147			raw, _ := frame.Encode(psk, probe)
148			echo, err := refl.Reflect(raw)
149			if err != nil {
150				t.Fatalf("reflect backup: %v", err)
151			}
152			m.handleInbound(m.paths[1], echo, ap1)
153			clk.advance(testProbeInterval - testProbeRTT)
154		}
155		if probers[0].State() != telemetry.StateDown {
156			t.Fatalf("blackholed primary state = %v, want down", probers[0].State())
157		}
158		if idx := scheduler.Pick(sched.ClassData); idx != 1 {
159			t.Fatalf("Pick = %d after primary blackhole, want 1 (failover to the runtime-added path)", idx)
160		}
161	}
