163	// TestMultipathRemovePathDrainsAndCloses is the T30 remove acceptance: removing a
164	// path closes its socket and drops it from the scheduler, while the surviving path,
165	// the virtual endpoint, and the connection-global outer-seq resequencing continue
166	// undisturbed — a DATA flow keeps being delivered on the remaining path.
167	func TestMultipathRemovePathDrainsAndCloses(t *testing.T) {
168		psk := testKey(t, 0x32)
169		clk := newFakeClock()
170		m, _, _ := newProbingMultipath(t, loopbackPaths(2), psk, clk)
171		fns, _, err := m.Open(0)
172		if err != nil {
173			t.Fatalf("Open: %v", err)
174		}
175		t.Cleanup(func() { _ = m.Close() })
176		fn := fns[0]
177	
178		virtBefore := m.virt
179		survivor := m.paths[0]
180		survivorAddr := survivor.conn.LocalAddr().(*net.UDPAddr)
181		removedConn := m.paths[1].conn
182	
183		recv := func() []byte {
184			bufs := [][]byte{make([]byte, 2048)}
185			sizes := make([]int, 1)
186			eps := make([]Endpoint, 1)
187			n, err := fn(bufs, sizes, eps)
188			if err != nil {
189				t.Fatalf("receive: %v", err)
190			}
191			if n != 1 {
192				t.Fatalf("receive n = %d, want 1", n)
193			}
194			return append([]byte(nil), bufs[0][:sizes[0]]...)
195		}
196	
197		// A DATA flow is delivered on the surviving path BEFORE the removal (pins the
198		// resequencer's release point at outer-seq 100).
199		sendDataSeqTo(t, psk, survivorAddr, 0, 100, []byte("pre-remove"))
200		if got := recv(); !bytes.Equal(got, []byte("pre-remove")) {
201			t.Fatalf("pre-remove delivery = %q, want %q", got, "pre-remove")
202		}
203	
204		// --- Remove the backup path at runtime. ---
205		if err := m.RemovePath("b"); err != nil {
206			t.Fatalf("RemovePath: %v", err)
207		}
208		if len(m.paths) != 1 {
209			t.Fatalf("paths = %d, want 1 after remove", len(m.paths))
210		}
211		if m.paths[0] != survivor {
212			t.Fatal("surviving path object changed on remove")
213		}
214		if m.virt != virtBefore {
215			t.Fatal("virtual endpoint object changed on remove")
216		}
217	
218		// The removed path's socket is closed: a write on it now fails.
219		if _, werr := removedConn.WriteToUDPAddrPort([]byte("x"), netip.MustParseAddrPort("127.0.0.1:9")); werr == nil {
220			t.Fatal("removed path socket still writable: it was not closed")
221		}
222	
223		// The flow continues on the surviving path with the NEXT outer-seq: the
224		// connection-global resequencing is not reset by the removal.
225		sendDataSeqTo(t, psk, survivorAddr, 0, 101, []byte("post-remove"))
226		if got := recv(); !bytes.Equal(got, []byte("post-remove")) {
227			t.Fatalf("post-remove delivery = %q, want %q (surviving path/resequencing disturbed)", got, "post-remove")
228		}
229	
230		// Cannot remove the last remaining path (would tear down the virtual endpoint).
231		if err := m.RemovePath("a"); err == nil {
232			t.Fatal("removing the last path succeeded, want refusal")
233		}
234		// Removing an unknown path errors.
235		if err := m.RemovePath("nope"); err == nil {
236			t.Fatal("removing an unknown path succeeded, want error")
237		}
238	}
