240	// TestMultipathRuntimePathSetRace is the crux concurrency guard (T30): runtime
241	// AddPath/RemovePath run CONCURRENTLY with the Send and receive hot paths and the
242	// probe loop. Under `go test -race` any unsynchronized access to the mutating path
243	// set / scheduler from the lock-free receive fan-in or the send path trips the
244	// detector; a clean run proves the mutation is serialized against them.
245	func TestMultipathRuntimePathSetRace(t *testing.T) {
246		psk := testKey(t, 0x33)
247		clk := newFakeClock()
248		m, _, _ := newProbingMultipath(t, loopbackPaths(1), psk, clk)
249		fns, _, err := m.Open(0)
250		if err != nil {
251			t.Fatalf("Open: %v", err)
252		}
253		fn := fns[0]
254	
255		peer0, ap0 := rawPeer(t)
256		m.paths[0].setRemote(ap0)
257		survivorAddr := m.paths[0].conn.LocalAddr().(*net.UDPAddr)
258	
259		var steady, drain sync.WaitGroup
260		stop := make(chan struct{})
261	
262		// Drainer: stands in for the engine's receive goroutine; exits on Close.
263		drain.Add(1)
264		go func() {
265			defer drain.Done()
266			bufs := [][]byte{make([]byte, 2048)}
267			sizes := make([]int, 1)
268			eps := make([]Endpoint, 1)
269			for {
270				if _, err := fn(bufs, sizes, eps); err != nil {
271					return
272				}
273			}
274		}()
275	
276		// Feeder: a monotonic DATA flow into the surviving path so the fan-in delivers.
277		steady.Add(1)
278		go func() {
279			defer steady.Done()
280			var seq atomic.Uint64
281			for {
282				select {
283				case <-stop:
284					return
285				default:
286				}
287				sendDataSeqTo(t, psk, survivorAddr, 0, seq.Add(1), []byte("d"))
288			}
289		}()
290	
291		// Sender: hammers the send hot path (Pick + m.paths read under m.mu).
292		steady.Add(1)
293		go func() {
294			defer steady.Done()
295			for {
296				select {
297				case <-stop:
298					return
299				default:
300				}
301				_ = m.Send([][]byte{[]byte("x")}, m.virt)
302			}
303		}()
304	
305		// Probe loop: snapshots the (mutating) path set under m.mu.
306		steady.Add(1)
307		go func() {
308			defer steady.Done()
309			for {
310				select {
311				case <-stop:
312					return
313				default:
314				}
315				m.emitProbes()
316			}
317		}()
318	
319		// Mutator (inline): add then remove a distinct path repeatedly, overlapping the
320		// steady-state hot paths. Each iteration is add+remove, so no path is left behind.
321		// 200 iterations against a 255-id space (boot uses id 0, so ids 1..200 are minted)
322		// never exhausts the id space, so any AddPath error here is UNEXPECTED. Fatal on it
323		// rather than break: a silent break on iteration 0 would let this crux race guard
324		// pass VACUOUSLY with zero add/remove coverage (masking an AddPath regression).
325		for i := 0; i < 200; i++ {
326			name := "rt-" + strconv.Itoa(i)
327			if err := m.AddPath(config.Path{Name: name, SourceAddr: netip.MustParseAddr("127.0.0.1")}); err != nil {
328				t.Fatalf("AddPath(%s) on iteration %d: %v (unexpected — the id space is not exhausted at 200 iters)", name, i, err)
329			}
330			if err := m.RemovePath(name); err != nil {
331				t.Fatalf("RemovePath(%s) on iteration %d: %v", name, i, err)
332			}
333		}
334	
335		close(stop)
336		steady.Wait() // feeder/sender/prober stopped; no AddPath is in flight now
337		_ = m.Close() // releases the drainer and retires all readers
338		drain.Wait()
339		_ = peer0
340	}
