342	// TestMultipathRuntimeRemoveSurvivesReopen is the T30 reopen-consistency regression
343	// (review criticism 1b): a runtime RemovePath must SURVIVE the amneziawg Close→Open
344	// lifecycle (Down/Up + IpcSet rebind). Before the fix, Open rebuilt m.paths from the
345	// stale m.defs and RESURRECTED the removed path with no scheduler entry — a
346	// probed-but-unselectable path that desynced the scheduler from the path slice. Now
347	// m.defs/m.probers track the removal and Open reconciles the scheduler, so the
348	// removed path stays gone and Pick still addresses the surviving path with no
349	// errNoHealthyPath.
350	func TestMultipathRuntimeRemoveSurvivesReopen(t *testing.T) {
351		psk := testKey(t, 0x34)
352		clk := newFakeClock()
353		m, probers, scheduler := newProbingMultipath(t, loopbackPaths(2), psk, clk) // "a","b"
354		if _, _, err := m.Open(0); err != nil {
355			t.Fatalf("Open: %v", err)
356		}
357		t.Cleanup(func() { _ = m.Close() })
358	
359		refl := telemetry.NewReflector(psk, rand.Reader)
360		codec, _ := frame.NewCodec(psk)
361	
362		// Bring both boot paths up.
363		peer0, ap0 := rawPeer(t)
364		peer1, ap1 := rawPeer(t)
365		m.paths[0].setRemote(ap0)
366		m.paths[1].setRemote(ap1)
367		for i := 0; i < testProbeUpSucc; i++ {
368			probeRound(t, m, clk, refl, codec, psk,
369				map[int]*net.UDPConn{0: peer0, 1: peer1}, map[int]netip.AddrPort{0: ap0, 1: ap1})
370		}
371		if probers[0].State() != telemetry.StateUp || probers[1].State() != telemetry.StateUp {
372			t.Fatalf("boot paths not both up: a=%v b=%v", probers[0].State(), probers[1].State())
373		}
374	
375		// Remove the backup path "b" at runtime.
376		if err := m.RemovePath("b"); err != nil {
377			t.Fatalf("RemovePath: %v", err)
378		}
379	
380		// --- Cycle Close→Open (the exact bind lifecycle amneziawg drives on Down/Up). ---
381		if err := m.Close(); err != nil {
382			t.Fatalf("Close: %v", err)
383		}
384		if _, _, err := m.Open(0); err != nil {
385			t.Fatalf("re-Open: %v", err)
386		}
387	
388		// The removed path stays gone: exactly one path, and it is "a".
389		if len(m.paths) != 1 {
390			t.Fatalf("paths after reopen = %d, want 1 (removed path was resurrected from stale m.defs)", len(m.paths))
391		}
392		if m.paths[0].name != "a" {
393			t.Fatalf("surviving path after reopen = %q, want \"a\"", m.paths[0].name)
394		}
395	
396		// Scheduler and path slice are consistent: Pick addresses the surviving path (a is
397		// still up — probers persist across reopen), never an out-of-range zombie index.
398		idx := scheduler.Pick(sched.ClassData)
399		if idx != 0 {
400			t.Fatalf("Pick after reopen = %d, want 0 (scheduler/path desync)", idx)
401		}
402		if idx >= len(m.paths) {
403			t.Fatalf("Pick returned out-of-range index %d for %d paths (frozen zombie entry)", idx, len(m.paths))
404		}
405	
406		// No errNoHealthyPath: a Send egresses on the surviving path once its remote is
407		// re-seeded on the fresh socket.
408		m.paths[0].setRemote(ap0)
409		if err := m.Send([][]byte{[]byte("post-reopen")}, m.virt); err != nil {
410			t.Fatalf("Send after reopen = %v, want nil (no errNoHealthyPath)", err)
411		}
412	}
