414	// TestMultipathRuntimeAddSurvivesReopen is the T30 reopen-consistency regression
415	// (review criticism 1a): a runtime AddPath must SURVIVE the Close→Open lifecycle. Before
416	// the fix, Open rebuilt m.paths from the stale m.defs (boot paths only), so the added
417	// path's prober was still in the scheduler at index N with NO path to Tick it: its
418	// liveness froze, Pick could pin to N, and Send's bounds check (N >= len(m.paths))
419	// rejected every datagram — total egress outage. Now m.defs/m.probers track the add and
420	// Open reconciles the scheduler, so the added path persists as a fully-wired, selectable
421	// path with no frozen zombie entry.
422	func TestMultipathRuntimeAddSurvivesReopen(t *testing.T) {
423		psk := testKey(t, 0x35)
424		clk := newFakeClock()
425		m, probers, scheduler := newProbingMultipath(t, loopbackPaths(1), psk, clk) // "a"
426		if _, _, err := m.Open(0); err != nil {
427			t.Fatalf("Open: %v", err)
428		}
429		t.Cleanup(func() { _ = m.Close() })
430	
431		refl := telemetry.NewReflector(psk, rand.Reader)
432		codec, _ := frame.NewCodec(psk)
433	
434		peer0, ap0 := rawPeer(t)
435		m.paths[0].setRemote(ap0)
436		for i := 0; i < testProbeUpSucc; i++ {
437			probeRound(t, m, clk, refl, codec, psk, map[int]*net.UDPConn{0: peer0}, map[int]netip.AddrPort{0: ap0})
438		}
439	
440		// Add a second path at runtime (starts down until its probes report healthy).
441		if err := m.AddPath(config.Path{Name: "runtime-b", SourceAddr: netip.MustParseAddr("127.0.0.1")}); err != nil {
442			t.Fatalf("AddPath: %v", err)
443		}
444		if len(m.paths) != 2 {
445			t.Fatalf("paths = %d, want 2 after add", len(m.paths))
446		}
447	
448		// --- Cycle Close→Open. ---
449		if err := m.Close(); err != nil {
450			t.Fatalf("Close: %v", err)
451		}
452		if _, _, err := m.Open(0); err != nil {
453			t.Fatalf("re-Open: %v", err)
454		}
455	
456		// The added path persists across the reopen at its slice index, with a live prober.
457		if len(m.paths) != 2 {
458			t.Fatalf("paths after reopen = %d, want 2 (runtime add did not survive)", len(m.paths))
459		}
460		if m.paths[1].name != "runtime-b" {
461			t.Fatalf("added path after reopen = %q, want \"runtime-b\"", m.paths[1].name)
462		}
463		if m.paths[1].prober == nil {
464			t.Fatal("added path lost its prober across the reopen")
465		}
466	
467		// No frozen zombie: the added path (index 1) starts DOWN after reopen (fresh socket,
468		// no echoes yet), so Pick selects the primary (index 0, still up), NEVER an
469		// out-of-range index, and Send succeeds on the primary.
470		if idx := scheduler.Pick(sched.ClassData); idx < 0 || idx >= len(m.paths) {
471			t.Fatalf("Pick after reopen = %d out of range [0,%d) (scheduler/path desync)", idx, len(m.paths))
472		} else if idx != 0 {
473			t.Fatalf("Pick after reopen = %d, want 0 (primary up, added path not yet healthy)", idx)
474		}
475		// Route this proof-of-egress Send to a throwaway sink so it does not pollute peer0's
476		// receive buffer (the probe reads below would otherwise mis-read the DATA frame),
477		// then restore the primary's real remote for the probe cadence.
478		sinkPeer, sinkAP := rawPeer(t)
479		m.paths[0].setRemote(sinkAP)
480		if err := m.Send([][]byte{[]byte("post-reopen")}, m.virt); err != nil {
481			t.Fatalf("Send after reopen = %v, want nil (frozen zombie would cause errNoHealthyPath)", err)
482		}
483		_ = sinkPeer
484		m.paths[0].setRemote(ap0)
485	
486		// Prove the reopened added path is fully wired (selectable, its prober Ticked), not a
487		// zombie: bring it up alongside the primary (it must NOT steal egress), then
488		// blackhole the primary and confirm egress fails over onto the reopened added path.
489		peer1, ap1 := rawPeer(t)
490		m.paths[1].setRemote(ap1)
491		for i := 0; i < testProbeUpSucc; i++ {
492			probeRound(t, m, clk, refl, codec, psk,
493				map[int]*net.UDPConn{0: peer0, 1: peer1}, map[int]netip.AddrPort{0: ap0, 1: ap1})
494		}
495		if probers[0].State() != telemetry.StateUp {
496			t.Fatalf("primary state after reopen = %v, want up", probers[0].State())
497		}
498		if m.paths[1].prober.State() != telemetry.StateUp {
499			t.Fatalf("reopened added path state = %v, want up (its prober is not being Ticked — frozen zombie)", m.paths[1].prober.State())
500		}
501		if idx := scheduler.Pick(sched.ClassData); idx != 0 {
502			t.Fatalf("Pick with both up = %d, want 0 (added path must not steal egress)", idx)
503		}
504		rounds := int(testProbeDownAfter/testProbeInterval) + 3
505		for i := 0; i < rounds; i++ {
506			m.emitProbes()
507			clk.advance(testProbeRTT)
508			readProbe(t, peer0, codec) // drain primary probe, no echo (blackhole)
509			probe := readProbe(t, peer1, codec)
510			raw, _ := frame.Encode(psk, probe)
511			echo, err := refl.Reflect(raw)
512			if err != nil {
513				t.Fatalf("reflect backup: %v", err)
514			}
515			m.handleInbound(m.paths[1], echo, ap1)
516			clk.advance(testProbeInterval - testProbeRTT)
517		}
518		if idx := scheduler.Pick(sched.ClassData); idx != 1 {
519			t.Fatalf("Pick after primary blackhole = %d, want 1 (failover onto the reopened runtime-added path)", idx)
520		}
521	}
522	
523	// TestMultipathRemoveReopenAddPathIDUnique is the T30 remove->reopen->add PathID
524	// high-water regression (review criticism, reproduced). A removal opens a gap in the
525	// stamp space while the survivor keeps its ORIGINAL higher prober PathID; before the
526	// fix Open reset the id counter to len(m.paths), so the next runtime AddPath re-minted
527	// a PathID that COLLIDED with the survivor's live stamp. Two live paths then emitted
528	// probes at the same (PathID, SessionID); the peer's Reflector keys anti-replay and
529	// the session challenge PER PathID, so the strict-monotonic replay filter dropped one
530	// of the two independent ProbeSeq streams -> probe loss / false-DOWN on the collided
531	// path. This asserts every live path carries a DISTINCT on-wire PathID (both its
532	// prober stamp and its DATA-frame pathState.id) across remove->reopen->add, and that
533	// the two agree per path. It FAILS on 8d81f2b (b and c both at PathID 1).
534	func TestMultipathRemoveReopenAddPathIDUnique(t *testing.T) {
535		psk := testKey(t, 0x36)
536		clk := newFakeClock()
537		m, _, _ := newProbingMultipath(t, loopbackPaths(2), psk, clk) // "a","b" -> stamps 0,1
538		if _, _, err := m.Open(0); err != nil {
539			t.Fatalf("Open: %v", err)
540		}
541		t.Cleanup(func() { _ = m.Close() })
542	
543		// Survivor "b" carries prober PathID 1; removing "a" opens the gap at stamp 0.
544		if got := m.paths[1].prober.PathID(); got != 1 {
545			t.Fatalf("boot path b prober PathID = %d, want 1", got)
546		}
547		if err := m.RemovePath("a"); err != nil {
548			t.Fatalf("RemovePath: %v", err)
549		}
550	
551		// Cycle Close->Open (the amneziawg Down/Up lifecycle) then admit a runtime path.
552		if err := m.Close(); err != nil {
553			t.Fatalf("Close: %v", err)
554		}
555		if _, _, err := m.Open(0); err != nil {
556			t.Fatalf("re-Open: %v", err)
557		}
558		if len(m.paths) != 1 || m.paths[0].name != "b" {
559			t.Fatalf("after reopen paths = %v, want [b]", pathNamesOf(m))
560		}
561		// Survivor keeps its ORIGINAL stamp across the reopen (never renumbered), and its
562		// DATA-frame id agrees with the prober stamp.
563		if got := m.paths[0].prober.PathID(); got != 1 {
564			t.Fatalf("survivor b prober PathID after reopen = %d, want 1 (stamp must be stable)", got)
565		}
566		if m.paths[0].id != m.paths[0].prober.PathID() {
567			t.Fatalf("survivor DATA id %d != prober stamp %d after reopen", m.paths[0].id, m.paths[0].prober.PathID())
568		}
569	
570		if err := m.AddPath(config.Path{Name: "c", SourceAddr: netip.MustParseAddr("127.0.0.1")}); err != nil {
571			t.Fatalf("AddPath: %v", err)
572		}
573		if len(m.paths) != 2 {
574			t.Fatalf("paths after add = %d, want 2", len(m.paths))
575		}
576	
577		// Every live path must carry a DISTINCT on-wire PathID, and its DATA-frame id must
578		// equal its prober stamp so DATA and PROBE agree on the wire.
579		seenProber := map[uint8]string{}
580		seenData := map[uint8]string{}
581		for _, ps := range m.paths {
582			if ps.id != ps.prober.PathID() {
583				t.Fatalf("path %q DATA id %d != prober stamp %d", ps.name, ps.id, ps.prober.PathID())
584			}
585			if other, dup := seenProber[ps.prober.PathID()]; dup {
586				t.Fatalf("prober PathID collision: paths %q and %q both stamp PathID %d "+
587					"(two live paths at identical (PathID,SessionID) -> cross-stream probe-replay drops)",
588					other, ps.name, ps.prober.PathID())
589			}
590			seenProber[ps.prober.PathID()] = ps.name
591			if other, dup := seenData[ps.id]; dup {
592				t.Fatalf("DATA-frame id collision: paths %q and %q both use pathState.id %d", other, ps.name, ps.id)
593			}
594			seenData[ps.id] = ps.name
595		}
596	}
597	
598	// pathNamesOf snapshots the active path names for a diagnostic message.
599	func pathNamesOf(m *Multipath) []string {
600		out := make([]string, len(m.paths))
601		for i, ps := range m.paths {
602			out[i] = ps.name
603		}
604		return out
605	}
606

