	idx := -1
	for i, pp := range p.paths {
		if pp.name == name {
			idx = i
			break
		}
	}
	if idx < 0 {
		return nil
	}
	if err := dyn.RemovePath(idx); err != nil {
		return err
	}
	p.paths = append(p.paths[:idx], p.paths[idx+1:]...)
	return nil
}

